const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

const logFile = path.join(__dirname, 'access.log');
const accessLogStream = fs.createWriteStream(logFile, { flags: 'a' });

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const sanitizeInput = (input) => {
    return input.replace(/[\r\n]+/g, '').replace(/[^a-zA-Z0-9_@.-]/g, '');
};

app.use(morgan(':remote-addr - :remote-user [:date[clf]] ":method :url" :status :res[content-length] - :response-time ms', {
    stream: accessLogStream,
    skip: (req, res) => res.statusCode < 400
}));

app.use((req, res, next) => {
    const username = sanitizeInput(req.body.username || 'anonymous');
    const ip = req.ip;
    const customHeader = sanitizeInput(req.headers['x-custom-header'] || 'none');
    
    const logMessage = `User: ${username}, IP: ${ip}, Custom Header: ${customHeader}`;
    accessLogStream.write(`${logMessage}\n`);
    
    next();
});

app.post('/log', (req, res) => {
    res.send('Log entry created.');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});